SELECT COUNT(DISTINCT S.PK_SIAPE) AS QUANTIDADE FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA C ON C.SIAPE = S.PK_SIAPE WHERE LOWER(S.CONTRATO) = LOWER('efetivos') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%engenharia civil%' AND C.ANO = 2024 AND C.SEMESTRE = 1 AND LOWER(C.SIGLA_CAMPUS) = LOWER('gyn') AND S.SAIU_DO_IFG = FALSE